+
+        assert_eq!(FcpError::NotConfigured.category(), ErrorCategory::Connector);
+        assert_eq!(FcpError::NotHandshaken.category(), ErrorCategory::Connector);
+        assert_eq!(
+            FcpError::InvalidRequest {
